import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const Dashboard = () => {
  const navigate = useNavigate();
  
  // States for the scheduler
  const [syllabus, setSyllabus] = useState('');
  const [targetDate, setTargetDate] = useState('');
  const [schedule, setSchedule] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) navigate('/login');
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('token');
    delete axios.defaults.headers.common['Authorization'];
    navigate('/login');
  };

  const generateSchedule = async () => {
    if (!syllabus || !targetDate) {
      alert("Please enter both the syllabus and a target date!");
      return;
    }

    setLoading(true);
    try {
      // Replace this URL with your actual backend endpoint later
      // const response = await axios.post('/api/generate-schedule', { syllabus, targetDate });
      
      // Mocking a response for now so you can see the UI work
      setTimeout(() => {
        setSchedule(`Based on your syllabus, you should focus on the first 3 topics until ${targetDate}.`);
        setLoading(false);
      }, 1500);
      
    } catch (err) {
      console.error(err);
      setLoading(false);
    }
  };

  return (
    <div style={{ fontFamily: 'Arial, sans-serif', backgroundColor: '#f9f9f9', minHeight: '100vh' }}>
      {/* Navbar */}
      <nav style={{ display: 'flex', justifyContent: 'space-between', padding: '15px 30px', background: '#2c3e50', color: 'white' }}>
        <h2 style={{ margin: 0 }}>StudyPulse</h2>
        <button onClick={handleLogout} style={{ background: '#e74c3c', color: 'white', border: 'none', padding: '8px 15px', borderRadius: '5px', cursor: 'pointer' }}>
          Logout
        </button>
      </nav>

      <div style={{ maxWidth: '800px', margin: '40px auto', padding: '20px', background: 'white', borderRadius: '10px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
        <h1 style={{ color: '#34495e' }}>Create Your Study Plan</h1>
        
        <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
          {/* Date Picker */}
          <div>
            <label style={{ fontWeight: 'bold', display: 'block', marginBottom: '8px' }}>Target Completion Date:</label>
            <input 
              type="date" 
              value={targetDate}
              onChange={(e) => setTargetDate(e.target.value)}
              style={{ width: '100%', padding: '10px', borderRadius: '5px', border: '1px solid #ddd' }}
            />
          </div>

          {/* Syllabus Textbox */}
          <div>
            <label style={{ fontWeight: 'bold', display: 'block', marginBottom: '8px' }}>Syllabus / Topics:</label>
            <textarea 
              placeholder="Paste your syllabus here (e.g., React Hooks, Node.js Middleware, MongoDB Aggregation...)"
              value={syllabus}
              onChange={(e) => setSyllabus(e.target.value)}
              style={{ width: '100%', height: '150px', padding: '10px', borderRadius: '5px', border: '1px solid #ddd', resize: 'vertical' }}
            />
          </div>

          {/* Generate Button */}
          <button 
            onClick={generateSchedule}
            disabled={loading}
            style={{ 
              backgroundColor: loading ? '#bdc3c7' : '#3498db', 
              color: 'white', 
              padding: '15px', 
              fontSize: '16px', 
              border: 'none', 
              borderRadius: '5px', 
              cursor: loading ? 'not-allowed' : 'pointer',
              transition: 'background 0.3s'
            }}
          >
            {loading ? 'Generating Strategy...' : 'Generate Study Schedule'}
          </button>
        </div>

        {/* Display Area for Generated Schedule */}
        {schedule && (
          <div style={{ marginTop: '30px', padding: '20px', backgroundColor: '#ecf0f1', borderRadius: '8px', borderLeft: '5px solid #3498db' }}>
            <h3 style={{ marginTop: 0 }}>Your Custom Plan:</h3>
            <p style={{ whiteSpace: 'pre-line' }}>{schedule}</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
